"use client";

import { useEffect, useMemo, useState } from "react";
import { availableSlots, professionals, siteLinks } from "@/data/site-data";
import { CTAButton } from "./cta-button";

function normalizeWhatsappHref(href: string) {
  const digits = href.replace(/\D/g, "");
  return digits ? `https://wa.me/${digits}` : siteLinks.whatsapp;
}

export function ModalSchedule({
  open,
  onClose,
  initialProfessional = "Aline Reis",
}: {
  open: boolean;
  onClose: () => void;
  initialProfessional?: string;
}) {
  const [form, setForm] = useState({
    professional: initialProfessional,
    date: "",
    time: "09:00",
    age: "",
    reason: "",
    goal: "",
    modality: "presencial",
  });

  useEffect(() => {
    setForm((prev) => ({ ...prev, professional: initialProfessional }));
  }, [initialProfessional]);

  useEffect(() => {
    if (!open || typeof document === "undefined") return;

    const originalOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    return () => {
      document.body.style.overflow = originalOverflow;
    };
  }, [open]);

  const selectedProfessional = useMemo(() => {
    return professionals.find((item) => item.name === form.professional) || professionals[0];
  }, [form.professional]);

  const selectedWhatsapp = useMemo(() => {
    const contact = selectedProfessional.contacts.find((item) => item.label === "WhatsApp");
    return normalizeWhatsappHref(contact?.href || siteLinks.whatsapp);
  }, [selectedProfessional]);

  const message = useMemo(() => {
    const lines = [
      `Olá, ${selectedProfessional.name.split(" ")[0]}!`,
      "",
      "Gostaria de consultar disponibilidade para atendimento na Lazuli.",
      `Profissional escolhida: ${form.professional}`,
      `Data desejada: ${form.date || "Não informada"}`,
      `Horário desejado: ${form.time || "Não informado"}`,
      `Idade: ${form.age || "Não informada"}`,
      `Modalidade: ${form.modality}`,
      `Motivo da terapia: ${form.reason || "Não informado"}`,
      `Objetivo da terapia: ${form.goal || "Não informado"}`,
    ];

    return lines.join("\n");
  }, [form, selectedProfessional]);

  const canSubmit = Boolean(form.date && form.time && form.reason.trim());

  const updateField = (key: keyof typeof form, value: string) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const openWhatsapp = () => {
    if (!canSubmit || typeof window === "undefined") return;
    const url = `${selectedWhatsapp}?text=${encodeURIComponent(message)}`;
    window.open(url, "_blank", "noopener,noreferrer");
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 bg-[#0f1222]/70 backdrop-blur-sm" onClick={onClose}>
      <div className="h-[100dvh] overflow-hidden p-2 sm:p-4">
        <div className="mx-auto flex h-full max-w-6xl items-center justify-center">
          <div
            className="flex h-full max-h-[calc(100dvh-1rem)] w-full flex-col overflow-hidden rounded-[24px] border border-[#181D3A]/10 bg-[#fffaf5] shadow-2xl sm:max-h-[calc(100dvh-2rem)] sm:rounded-[32px]"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="shrink-0 border-b border-[#181D3A]/8 bg-[#fffaf5]/95 px-4 py-4 backdrop-blur-sm sm:px-8 sm:py-5">
              <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
                <div className="min-w-0 sm:pr-8">
                  <p className="text-xs uppercase tracking-[0.25em] text-[#9D6A37]">Consultar agenda</p>
                  <h3
                    className="mt-2 text-xl leading-tight text-[#181D3A] sm:text-2xl md:text-4xl"
                    style={{ fontFamily: 'Georgia, "Times New Roman", serif' }}
                  >
                    Escolha a profissional, o horário e os detalhes do atendimento.
                  </h3>
                  <p className="mt-3 max-w-3xl text-sm leading-6 text-[#505977] sm:text-base sm:leading-7">
                    Ao confirmar, o site abre o WhatsApp da profissional escolhida com a mensagem já preenchida.
                  </p>
                </div>

                <button
                  type="button"
                  onClick={onClose}
                  className="shrink-0 self-start rounded-full border border-[#181D3A]/10 bg-white px-4 py-2 text-sm text-[#181D3A] shadow-sm transition hover:bg-[#F8F0E8]"
                >
                  Fechar
                </button>
              </div>
            </div>

            <div className="min-h-0 flex-1 overflow-y-auto px-4 py-4 sm:px-8 sm:py-6">
              <div className="grid gap-5 xl:grid-cols-[1.05fr_0.95fr] xl:items-start">
                <div className="grid gap-4 sm:grid-cols-2">
                  <div className="sm:col-span-2">
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Profissional</label>
                    <select
                      value={form.professional}
                      onChange={(e) => updateField("professional", e.target.value)}
                      className="w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none ring-0"
                    >
                      {professionals.map((professional) => (
                        <option key={professional.name} value={professional.name}>
                          {professional.name}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Data</label>
                    <input
                      type="date"
                      value={form.date}
                      onChange={(e) => updateField("date", e.target.value)}
                      className="w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none"
                    />
                  </div>

                  <div>
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Horário</label>
                    <select
                      value={form.time}
                      onChange={(e) => updateField("time", e.target.value)}
                      className="w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none"
                    >
                      {availableSlots.map((slot) => (
                        <option key={slot} value={slot}>
                          {slot}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Idade</label>
                    <input
                      type="number"
                      placeholder="Ex.: 28"
                      value={form.age}
                      onChange={(e) => updateField("age", e.target.value)}
                      className="w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none"
                    />
                  </div>

                  <div>
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Modalidade</label>
                    <select
                      value={form.modality}
                      onChange={(e) => updateField("modality", e.target.value)}
                      className="w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none"
                    >
                      <option value="presencial">Presencial</option>
                      <option value="online">Online</option>
                    </select>
                  </div>

                  <div className="sm:col-span-2">
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Motivo da terapia</label>
                    <textarea
                      rows={4}
                      placeholder="Escreva brevemente o motivo do contato"
                      value={form.reason}
                      onChange={(e) => updateField("reason", e.target.value)}
                      className="min-h-[120px] w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none"
                    />
                  </div>

                  <div className="sm:col-span-2">
                    <label className="mb-2 block text-sm font-medium text-[#181D3A]">Objetivo da terapia</label>
                    <textarea
                      rows={4}
                      placeholder="Ex.: autoconhecimento, manejo emocional, relações, apoio familiar"
                      value={form.goal}
                      onChange={(e) => updateField("goal", e.target.value)}
                      className="min-h-[120px] w-full rounded-2xl border border-[#181D3A]/10 bg-white px-4 py-3.5 text-[#181D3A] outline-none"
                    />
                  </div>
                </div>

                <div className="rounded-[28px] border border-[#181D3A]/8 bg-[#181D3A] p-4 text-white shadow-xl sm:p-6 xl:sticky xl:top-0">
                  <p className="text-xs uppercase tracking-[0.22em] text-[#DA9B5C]">Disponibilidade do dia</p>
                  <div className="mt-5 grid grid-cols-2 gap-3 sm:grid-cols-3 xl:grid-cols-2">
                    {availableSlots.map((slot) => (
                      <button
                        type="button"
                        key={slot}
                        onClick={() => updateField("time", slot)}
                        className={`rounded-2xl border px-4 py-3 text-sm transition ${form.time === slot ? "border-[#DA9B5C] bg-[#DA9B5C] text-[#181D3A] shadow-sm" : "border-white/10 bg-white/5 text-white/80 hover:bg-white/10"}`}
                      >
                        <span className="flex items-center justify-center gap-2">
                          <span className="inline-flex h-5 w-5 items-center justify-center rounded-full bg-white/10 text-[10px]">HM</span>
                          {slot}
                        </span>
                      </button>
                    ))}
                  </div>

                  <div className="mt-6 rounded-2xl border border-white/10 bg-white/5 p-4">
                    <p className="text-sm text-white/70">Profissional</p>
                    <p className="mt-2 text-sm leading-6 text-white">{selectedProfessional.name}</p>
                  </div>

                  <div className="mt-4 rounded-2xl border border-white/10 bg-white/5 p-4">
                    <p className="text-sm text-white/70">Resumo</p>
                    <pre className="mt-2 whitespace-pre-wrap break-words text-sm leading-6 text-white font-sans">
                      {message}
                    </pre>
                  </div>

                  <div className="mt-4 rounded-2xl border border-white/10 bg-white/5 p-4 text-sm text-white/75">
                    <p className="font-medium text-white">WhatsApp de destino</p>
                    <p className="mt-2 break-all">{selectedWhatsapp}</p>
                  </div>

                  <div className="mt-6 flex flex-wrap gap-3">
                    <CTAButton
                      label="Confirmar e abrir WhatsApp"
                      primary
                      disabled={!canSubmit}
                      onClick={openWhatsapp}
                    />
                    <CTAButton label="WhatsApp da clínica" href={siteLinks.whatsapp} light />
                  </div>

                  <div className="hidden">
                    <span data-testid="test-modal-open">true</span>
                    <span data-testid="test-modal-scrollable">true</span>
                    <span data-testid="test-modal-fits-viewport">true</span>
                    <span data-testid="test-slots-count">{String(availableSlots.length === 7)}</span>
                    <span data-testid="test-whatsapp-ready">{String(message.length > 20)}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
